class Solution {
    public String getHint(String secret, String guess) {
        int bulls = countBulls(secret, guess);
        int cows = countCows(secret, guess);
        return bulls + "A" + cows;
    }

    public int countBulls(String secret, String guess) {
        int bulls = 0;
        for (int i = 0; i < secret.length(); i++) {
            if (secret.charAt(i) == guess.charAt(i)) {
                bulls++;
            }
        }
        return bulls;
    }

    public int countCows(String secret, String guess) {
        int cows = 0;
        for (int i = 0; i < secret.length(); i++) {
            if (secret.charAt(i) == guess.charAt(i)) {
                cows++;
            }
        }
        return cows;
    }
}
```

